#!/usr/bin/env node
import { mkdir, readdir, readFile, writeFile } from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const MAX_BADGE_SCRIPT_BYTES = 256 * 1024;
const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const orpgDir = path.join(root, 'oRPG');

function parseArgs(argv) {
	const opts = {
		allowOversize: false,
		maxBytes: MAX_BADGE_SCRIPT_BYTES,
		out: path.join(orpgDir, 'dist'),
		perScreen: false,
		screens: null,
		strip: true
	};

	for (let i = 0; i < argv.length; i += 1) {
		const arg = argv[i];
		if (arg === '--allow-oversize') opts.allowOversize = true;
		else if (arg === '--no-strip') opts.strip = false;
		else if (arg === '--per-screen') opts.perScreen = true;
		else if (arg === '--out') opts.out = path.resolve(root, argv[++i]);
		else if (arg.startsWith('--out=')) opts.out = path.resolve(root, arg.slice('--out='.length));
		else if (arg === '--max-bytes') opts.maxBytes = Number(argv[++i]);
		else if (arg.startsWith('--max-bytes=')) opts.maxBytes = Number(arg.slice('--max-bytes='.length));
		else if (arg === '--screen' || arg === '--screens') opts.screens = argv[++i];
		else if (arg.startsWith('--screen=')) opts.screens = arg.slice('--screen='.length);
		else if (arg.startsWith('--screens=')) opts.screens = arg.slice('--screens='.length);
		else if (arg === '--help' || arg === '-h') {
			printHelp();
			process.exit(0);
		} else {
			throw new Error(`Unknown argument: ${arg}`);
		}
	}

	if (!Number.isFinite(opts.maxBytes) || opts.maxBytes <= 0) {
		throw new Error('--max-bytes must be a positive number');
	}
	if (!opts.perScreen && !opts.screens) opts.screens = 'all';
	return opts;
}

function printHelp() {
	console.log(`Usage:
  node scripts/bundle-orpg.js
  node scripts/bundle-orpg.js --per-screen [--out oRPG/dist]
  node scripts/bundle-orpg.js --screen 0.1 --out oRPG/dist/oRPG-0_1.bundle.lua
  node scripts/bundle-orpg.js --screens all --out oRPG/dist/oRPG.bundle.lua

Options:
  --per-screen       Write one bundle per challenge screen.
  --screen <id>      Bundle one screen id, e.g. 0.1 or 0_1.
  --screens <list>   Comma-separated ids, or "all". Default: all.
  --out <path>       Output file for single/all mode, directory for per-screen.
  --no-strip         Keep comments and blank lines.
  --max-bytes <n>    Badge size limit. Default: ${MAX_BADGE_SCRIPT_BYTES}.
  --allow-oversize   Do not fail when output exceeds --max-bytes.
`);
}

async function luaFilesIn(dir) {
	const names = await readdir(path.join(orpgDir, dir));
	return names
		.filter((name) => name.endsWith('.lua'))
		.sort()
		.map((name) => path.join(orpgDir, dir, name));
}

function screenIdFromFile(file) {
	return path.basename(file, '.lua');
}

function normalizeScreenId(id) {
	return id.trim().replace(/\./g, '_');
}

function moduleName(file) {
	const rel = path.relative(orpgDir, file).replaceAll(path.sep, '/').replace(/\.lua$/, '');
	return rel.replaceAll('/', '.');
}

function stripLua(source) {
	const lines = source.replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');
	const out = [];
	let inLongString = false;

	for (const line of lines) {
		let rest = line;
		if (!inLongString) {
			const trimmed = line.trim();
			if (trimmed === '' || trimmed.startsWith('--')) continue;
			rest = line.replace(/[ \t]+$/g, '');
		}

		for (let i = 0; i < rest.length; i += 1) {
			if (!inLongString && rest.slice(i, i + 2) === '[[') {
				inLongString = true;
				i += 1;
			} else if (inLongString && rest.slice(i, i + 2) === ']]') {
				inLongString = false;
				i += 1;
			}
		}

		out.push(rest);
	}

	return out.join('\n') + '\n';
}

async function readLua(file, strip) {
	const source = await readFile(file, 'utf8');
	return strip ? stripLua(source) : source.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
}

async function buildBundle({ files, strip }) {
	const chunks = [
		'-- Generated by scripts/bundle-orpg.js. Do not edit by hand.\n',
		'-- Upload this single file to the Onion OS Lua Script Registry.\n',
		'package.preload = package.preload or {}\n\n'
	];

	for (const file of files.modules) {
		const name = moduleName(file);
		const source = await readLua(file, strip);
		chunks.push(`package.preload[${JSON.stringify(name)}] = function(...)\n`);
		chunks.push(source);
		if (!source.endsWith('\n')) chunks.push('\n');
		chunks.push('end\n\n');
	}

	chunks.push(await readLua(files.entry, strip));
	return chunks.join('');
}

async function writeBundle(outFile, bundle, opts) {
	await mkdir(path.dirname(outFile), { recursive: true });
	await writeFile(outFile, bundle);

	const bytes = Buffer.byteLength(bundle, 'utf8');
	const rel = path.relative(root, outFile);
	const status = bytes <= opts.maxBytes ? 'OK' : 'OVERSIZE';
	console.log(`${status} ${rel} ${bytes}/${opts.maxBytes} bytes`);
	if (bytes > opts.maxBytes && !opts.allowOversize) return false;
	return true;
}

async function main() {
	const opts = parseArgs(process.argv.slice(2));
	const libs = await luaFilesIn('lib');
	const screens = (await luaFilesIn('screens')).filter((file) => screenIdFromFile(file) !== '_template');
	const entry = path.join(orpgDir, 'oRPG.lua');

	const screenMap = new Map(screens.map((file) => [screenIdFromFile(file), file]));
	let ok = true;

	if (opts.perScreen) {
		for (const screen of screens) {
			const id = screenIdFromFile(screen);
			const bundle = await buildBundle({ files: { entry, modules: [...libs, screen] }, strip: opts.strip });
			const outFile = path.join(opts.out, `oRPG-${id}.bundle.lua`);
			ok = (await writeBundle(outFile, bundle, opts)) && ok;
		}
	} else {
		let selectedScreens;
		if (opts.screens === 'all') {
			selectedScreens = screens;
		} else {
			selectedScreens = opts.screens.split(',').map((id) => {
				const normalized = normalizeScreenId(id);
				const file = screenMap.get(normalized);
				if (!file) throw new Error(`Unknown screen id: ${id}`);
				return file;
			});
		}

		const bundle = await buildBundle({ files: { entry, modules: [...libs, ...selectedScreens] }, strip: opts.strip });
		const defaultName =
			opts.screens === 'all'
				? 'oRPG.bundle.lua'
				: `oRPG-${selectedScreens.map(screenIdFromFile).join('-')}.bundle.lua`;
		const outFile = opts.out.endsWith('.lua') ? opts.out : path.join(opts.out, defaultName);
		ok = await writeBundle(outFile, bundle, opts);
	}

	if (!ok) {
		console.error('One or more bundles exceed the badge script limit. Use --allow-oversize only for non-badge targets.');
		process.exit(1);
	}
}

main().catch((err) => {
	console.error(err.message);
	process.exit(1);
});
